INSERT INTO word_senses (id, word_id, part_of_speech, sense_order, definition_en, example_en) VALUES
  ('50f09ea8-80c9-5aeb-8abf-4c6dcc4fcd94', '3acee99a-3b3d-58ae-8396-e5a06880108f', 'verb', 1, 'have the quality of being; (copula, used with an adjective or a predicate noun)', 'John is rich'),
  ('f5df9202-64bb-53de-9cbb-514970270d9f', '3acee99a-3b3d-58ae-8396-e5a06880108f', 'verb', 2, 'be identical to; be someone or something', 'The president of the company is John Smith'),
  ('12b1b544-6b4e-5ae3-b195-6f542647175f', 'b15f4d2c-2d23-51a2-a087-75ea389f7376', 'verb', 1, 'have or possess, either in a concrete or an abstract sense', 'She has $1,000 in the bank'),
  ('65bc975b-df18-5880-b190-2bb08c5f7b5d', 'b15f4d2c-2d23-51a2-a087-75ea389f7376', 'verb', 2, 'have as a feature', 'This restaurant features the most famous chefs in France'),
  ('743adb23-bd00-52db-8b38-3d4727643300', 'f4f87c00-04a2-5671-98fc-fa3a59b3de12', 'adverb', 1, 'negation of a word or group of words', 'he does not speak French'),
  ('1e8570fa-d29c-5ee1-b5ac-fd29a6ceced5', '73a8ac62-61a9-5f7a-8f07-88e1f0cd6ec8', 'adverb', 1, 'to a very great extent or degree', 'the idea is so obvious'),
  ('5e5b8796-5ccb-576a-bfe4-cffef836cbe5', '73a8ac62-61a9-5f7a-8f07-88e1f0cd6ec8', 'adverb', 2, 'in a manner that facilitates', 'he observed the snakes so he could describe their behavior'),
  ('1f100bad-c828-53f0-8ee6-c9a08572dce8', '310c2fa9-d556-59b0-8838-74235d45c640', 'verb', 1, 'preserve in a can or tin', 'tinned foods are not very tasty'),
  ('045d908e-7f1b-512b-a2c5-653ced04fe8c', '310c2fa9-d556-59b0-8838-74235d45c640', 'verb', 2, 'terminate the employment of; discharge from an office or position', 'The boss fired his secretary today'),
  ('faffdcef-71ec-52bd-ba86-4319918a329d', 'add8c8ab-2bb7-5b4c-b5d1-b2a3f615a128', 'verb', 1, 'decree or ordain', 'God wills our existence'),
  ('c9857b5a-8fe9-568d-8a31-1b0c9623d847', 'add8c8ab-2bb7-5b4c-b5d1-b2a3f615a128', 'verb', 2, 'determine by choice', 'This action was willed and intended'),
  ('9c939a37-4075-5a15-9a50-9476734edde5', 'c3a0c274-17b7-5452-95fe-e00c6ca0c94c', 'adverb', 1, 'and nothing more', 'I was merely asking'),
  ('b8099537-779b-5411-a163-2daec8fc2971', 'c3a0c274-17b7-5452-95fe-e00c6ca0c94c', 'adverb', 2, 'indicating exactness or preciseness', 'he was doing precisely (or exactly) what she had told him to do'),
  ('8a3d6b8c-5549-5080-a08a-2d44c623b7d2', '60ce3736-686c-5583-9c7c-46f43548e74b', 'adjective', 1, '(comparative of `much'' used with mass nouns) a quantifier meaning greater in size or amount or extent or degree', 'more land'),
  ('12c79556-8547-5194-a0d1-433a056ec520', '60ce3736-686c-5583-9c7c-46f43548e74b', 'adjective', 2, '(comparative of `many'' used with count nouns) quantifier meaning greater in number', 'a hall with more seats'),
  ('5d69a005-0b63-593a-a088-8c169bd48be7', '60ce3736-686c-5583-9c7c-46f43548e74b', 'adverb', 1, 'used to form the comparative of some adjectives and adverbs', 'more interesting'),
  ('24986c6c-df1a-5c32-ac02-666ff5cee6e8', '60ce3736-686c-5583-9c7c-46f43548e74b', 'adverb', 2, 'comparative of much; to a greater degree or extent', 'he works more now'),
  ('3b89aaec-3f3b-5102-b8f4-703a9a681047', '29c2daec-2ba6-5ea2-96cc-68c03a775f76', 'verb', 1, 'engage in', 'make love, not war'),
  ('dc7b8bb9-f48d-552f-b982-76e5701e1c19', '29c2daec-2ba6-5ea2-96cc-68c03a775f76', 'verb', 2, 'carry out or perform an action', 'John did the painting, the weeding, and he cleaned out the gutters'),
  ('8a4a289b-6e15-5995-8f83-c9cb1ba9c14b', '7a0c3f74-dd9f-5323-82d6-84a0669402b5', 'noun', 1, 'an instance or single occasion for some event', 'this time he succeeded'),
  ('85b197ae-82fa-5a16-b48e-8959cc20329e', '7a0c3f74-dd9f-5323-82d6-84a0669402b5', 'noun', 2, 'a period of time considered as a resource under your control and sufficient to accomplish something', 'take time to smell the roses'),
  ('4fa7962f-0527-5231-86ae-e7adcb123b67', '4d5f776c-4514-5dd1-b6bc-525eb3ce86f8', 'verb', 1, 'come into the possession of something concrete or abstract', 'She got a lot of paintings from her uncle'),
  ('ae027ac8-9875-5e86-8cc4-26c7fdbeaaab', '4d5f776c-4514-5dd1-b6bc-525eb3ce86f8', 'verb', 2, 'enter or assume a certain state or condition', 'He became annoyed when he heard the bad news'),
  ('c32492ee-6149-5386-b835-170f21cf9b22', '70ea531c-cd7b-51a5-9b23-0c38466cb21f', 'adjective', 1, 'not of long duration; having just (or relatively recently) come into being or been made or acquired or discovered', 'a new law'),
  ('f0e7adef-1e3d-5a30-a67c-1d8793991e58', '70ea531c-cd7b-51a5-9b23-0c38466cb21f', 'adjective', 2, 'original and of a kind not seen before', 'the computer produced a completely novel proof of a well-known theorem'),
  ('f5d4984d-ee52-5c6b-9619-10646061da93', 'ac4bc584-5606-59be-962f-aa05878f164b', 'noun', 1, '(plural) any group of human beings (men or women or children) collectively', 'old people'),
  ('44e0be5d-6297-5149-b3b9-5bc82dc90a97', 'ac4bc584-5606-59be-962f-aa05878f164b', 'noun', 2, 'the body of citizens of a state or country', 'the Spanish people'),
  ('06c88cd2-0352-5bdd-8a73-3d21fbab39bb', '684aa046-3a24-570a-bfb2-544482c49ff5', 'adverb', 1, 'in addition', 'he has a Mercedes, too'),
  ('10ee5415-9b90-53fb-ba89-c7705cd184a1', 'e0eeaf82-f8e2-5114-b0ac-7bb3bc23ba08', 'adverb', 1, 'in the historical present; at this point in the narration of a series of past events', 'President Kennedy now calls in the National Guard'),
  ('4984b9f7-8995-5c58-b230-96edcb592b97', 'e0eeaf82-f8e2-5114-b0ac-7bb3bc23ba08', 'adverb', 2, 'in these times; - Nancy Mitford', 'it is solely by their language that the upper classes nowadays are distinguished'),
  ('72e8deb3-54f4-57d9-a4c4-b6cdc02bc51d', '5c7cc554-5706-5f4a-a76c-3418b1d81648', 'adjective', 1, 'not the same one or ones already mentioned or implied; - the White Queen', 'today isn''t any other day'),
  ('de6c5229-f0b0-5533-a9b8-13a74b9292a8', '5c7cc554-5706-5f4a-a76c-3418b1d81648', 'adjective', 2, 'recently past', 'the other evening'),
  ('b46d1050-7949-52ba-bb0a-0f8983b1a8f8', '9ddac70a-d470-50f0-aa7b-932444805c74', 'adjective', 1, 'having desirable or positive qualities especially those suitable for a thing specified', 'good news from the hospital'),
  ('25c0af40-176b-5e29-84d7-400845f7ecdd', '9ddac70a-d470-50f0-aa7b-932444805c74', 'adjective', 2, 'having the normally expected amount', 'gives full measure'),
  ('ac73a03b-2fd0-5427-9491-df8cc55c5b21', 'e00ebd2d-d0ce-5343-bbca-d50596de9da5', 'adjective', 1, 'being the only one; single and isolated from others', 'the lone doctor in the entire county'),
  ('c9b97ffe-fb8d-50b4-a47c-42aba6f2abdf', 'e00ebd2d-d0ce-5343-bbca-d50596de9da5', 'adjective', 2, 'exclusive of anyone or anything else', 'she alone believed him'),
  ('03d07507-6043-5cd1-85a6-c4fb597c52d9', 'e00ebd2d-d0ce-5343-bbca-d50596de9da5', 'adverb', 1, 'and nothing more', 'I was merely asking'),
  ('5c7ecdd8-251e-5deb-8ed1-2c835d5482ac', 'e00ebd2d-d0ce-5343-bbca-d50596de9da5', 'adverb', 2, 'without any others being included or involved', 'was entirely to blame'),
  ('e4de2955-978a-53c2-8e40-d3f9c10cb570', '2bd1ffbe-6ebe-55a7-b835-b6d709e24fa0', 'adjective', 1, 'preceding all others in time or space or degree', 'the first house on the right'),
  ('5c04f8bb-0244-5d99-920d-9c60f3453679', '2bd1ffbe-6ebe-55a7-b835-b6d709e24fa0', 'adjective', 2, 'indicating the beginning unit in a series', NULL),
  ('dd7bfcf0-26fb-5b4a-90e1-982220d5bf81', '2bd1ffbe-6ebe-55a7-b835-b6d709e24fa0', 'adverb', 1, 'before anything else', 'first we must consider the garter snake'),
  ('db298aa3-b3cc-5289-bad8-91de275dd0f9', '2bd1ffbe-6ebe-55a7-b835-b6d709e24fa0', 'adverb', 2, 'the initial time', 'when Felix first saw a garter snake'),
  ('b132d144-098f-5b10-a03d-ff6f35a0c40f', '1ea94745-d4cd-5d81-b832-9c5bfadcf2e1', 'verb', 1, 'be cognizant or aware of a fact or a specific piece of information; possess knowledge or information about', 'I know that the President lied to the people'),
  ('ba19312c-b541-5e4a-9507-3e35824e0411', '1ea94745-d4cd-5d81-b832-9c5bfadcf2e1', 'verb', 2, 'know how to do or perform something', 'She knows how to knit'),
  ('8cf44e55-f95c-5b1c-9fd9-c9bf9976fae3', '9720f2ce-6160-5b24-aa79-b80019845eca', 'verb', 1, 'perceive by sight or have the power to perceive by sight', 'You have to be a good observer to see all the details'),
  ('8c0b5344-499e-567e-b726-2b173111b4da', '9720f2ce-6160-5b24-aa79-b80019845eca', 'verb', 2, 'perceive (an idea or situation) mentally', 'Now I see!'),
  ('c829cdad-351c-556d-987d-ffe047640c35', 'a19440ae-1de5-543f-8beb-f1007a93ebb2', 'verb', 1, 'engage in', 'make love, not war'),
  ('e747935d-0fcb-5f00-9111-df19ec4d1d04', 'a19440ae-1de5-543f-8beb-f1007a93ebb2', 'verb', 2, 'give certain properties to something', 'get someone mad'),
  ('a63cb129-c8b8-5237-8c4c-502e34cf8936', '439bfc22-6974-5ecc-a2c4-a7c317da370b', 'verb', 1, 'judge or regard; look upon; judge', 'I think he is very smart'),
  ('dfc9b4d2-2873-5679-aaa1-62a4846af228', '439bfc22-6974-5ecc-a2c4-a7c317da370b', 'verb', 2, 'expect, believe, or suppose', 'I imagine she earned a lot of money with her new novel'),
  ('e3cd4b08-264e-5f6a-907c-619e6dd23585', '59b15b35-f64b-5ab5-98df-377d93138836', 'adverb', 1, 'subsequently or soon afterward (often used as sentence connectors)', 'then he left'),
  ('e3c6ffab-4dac-5b71-bba5-19abb7b312ec', '59b15b35-f64b-5ab5-98df-377d93138836', 'adverb', 2, 'in that case or as a consequence', 'if he didn''t take it, then who did?'),
  ('50587e38-995d-5927-b4b5-368f72e2f226', '0dfcc20b-f927-5b6f-97c4-c87a86f1289c', 'noun', 1, 'the posterior part of a human (or animal) body from the neck to the end of the spine', 'his back was nicely tanned'),
  ('c3a26473-5275-503f-be19-d262274a1627', '0dfcc20b-f927-5b6f-97c4-c87a86f1289c', 'noun', 2, 'the side that goes last or is not normally seen', 'he wrote the date on the back of the photograph'),
  ('38ce9006-bd77-53f1-8139-13c6218904e7', '0dfcc20b-f927-5b6f-97c4-c87a86f1289c', 'adverb', 1, 'in or to or toward a former location', 'she went back to her parents'' house'),
  ('2223bf46-2479-5260-b396-b23c78ea8388', '0dfcc20b-f927-5b6f-97c4-c87a86f1289c', 'adverb', 2, 'at or to or toward the back or rear', 'he moved back'),
  ('b5e73723-4daf-5db3-94e5-9db92d0384e5', '8de61449-7ccc-52a4-aeb4-103995f295f6', 'verb', 1, 'feel or have a desire for; want strongly', 'I want to go home now'),
  ('e7679a8c-4097-5c03-ba17-18d096a0f546', '8de61449-7ccc-52a4-aeb4-103995f295f6', 'verb', 2, 'have need of', 'This piano wants the attention of a competent tuner'),
  ('da8c12ac-e531-59a6-b908-6ba9289dbb8c', '57387f7b-0abb-585b-9c74-6d56048ce626', 'verb', 1, 'change location; move, travel, or proceed, also metaphorically', 'How fast does your new car go?'),
  ('58794477-2cf6-54f5-8e27-fe875ff37086', '57387f7b-0abb-585b-9c74-6d56048ce626', 'verb', 2, 'follow a procedure or take a course', 'We should go farther in this matter'),
  ('c57f95b8-e805-5c29-a901-495b548af2fc', '84183b70-9d1b-51f7-836e-2dc794cf6d76', 'adverb', 1, '(often used as a combining form) in a good or proper or satisfactory manner or to a high standard (`good'' is a nonstandard dialectal variant for `well'')', 'the children behaved well'),
  ('d19e7f73-6d7f-5f94-a802-43916282bbbd', '84183b70-9d1b-51f7-836e-2dc794cf6d76', 'adverb', 2, 'thoroughly or completely; fully; often used as a combining form; ; ; ; ; ,', 'The problem is well understood'),
  ('3c8476be-cd48-5624-94b9-b2060b8b5ee4', '080caf5a-e085-5c76-8beb-6a9ca2fee98f', 'verb', 1, 'express in words', 'He said that he wanted to marry her'),
  ('3127781c-f2ae-5615-9ddd-1d59aaa95553', '080caf5a-e085-5c76-8beb-6a9ca2fee98f', 'verb', 2, 'report or maintain', 'He alleged that he was the victim of a crime'),
  ('5846e162-22a1-5bac-8667-a87c224dc12f', 'cc604b64-d558-52bb-83a8-a849a9b33d60', 'noun', 1, 'how something is done or how it happens', 'her dignified manner'),
  ('17ab4507-83d7-53ba-ba7d-723f0533374f', 'cc604b64-d558-52bb-83a8-a849a9b33d60', 'noun', 2, 'how a result is obtained or an end is achieved', 'a means of control'),
  ('6c6ca7da-1948-5549-a4d3-c2272849f245', 'c7cced5c-b07d-549b-9f83-589d13f8edfc', 'adjective', 1, '(superlative of `many'' used with count nouns and often preceded by `the'') quantifier meaning the greatest in number', 'who has the most apples?'),
  ('5ee91dcd-cad1-5190-a1dc-ba0f728dcadb', 'c7cced5c-b07d-549b-9f83-589d13f8edfc', 'adjective', 2, 'the superlative of `much'' that can be used with mass nouns and is usually preceded by `the''; a quantifier meaning the greatest in amount or extent or degree', 'made the most money he could'),
  ('2e288a8b-b6ab-5235-91a7-9cfe1cd6e4f0', 'c7cced5c-b07d-549b-9f83-589d13f8edfc', 'adverb', 1, 'used to form the superlative', 'the king cobra is the most dangerous snake'),
  ('f3422d14-d528-5599-8a37-f0f5e08da0a1', 'c7cced5c-b07d-549b-9f83-589d13f8edfc', 'adverb', 2, 'very', 'a most welcome relief'),
  ('6d6af76c-2a82-5313-99fe-122cd17b6627', 'ab264f81-0671-5252-8ed1-71d633835228', 'adjective', 1, '(quantifier used with mass nouns) great in quantity or degree or extent', 'not much rain'),
  ('ef7a20d1-4ec2-5a4e-996f-be2d6e6e47d1', 'ab264f81-0671-5252-8ed1-71d633835228', 'adverb', 1, 'to a great degree or extent', 'she''s much better now'),
  ('672be32a-d637-5098-ba9d-14780a963b4b', 'ab264f81-0671-5252-8ed1-71d633835228', 'adverb', 2, 'very', 'he was much annoyed'),
  ('9f32e48d-fc13-50ce-88a3-c855f4a00729', '77693239-97ce-588f-9bef-c117c0c1d8f9', 'adjective', 1, 'precisely as stated', 'the very center of town'),
  ('5ccefa2c-bb3e-59a4-a4a8-a4da7a4a8c4e', '77693239-97ce-588f-9bef-c117c0c1d8f9', 'adjective', 2, 'being the exact same one; not any other:', 'this is the identical room we stayed in before'),
  ('de5d6631-ff6b-5f9c-97b1-27900ace5785', '77693239-97ce-588f-9bef-c117c0c1d8f9', 'adverb', 1, 'used as intensifiers; `real'' is sometimes used informally for `really''; `rattling'' is informal', 'she was very gifted'),
  ('373c49a8-7d93-5275-9e23-484998f05a6d', '77693239-97ce-588f-9bef-c117c0c1d8f9', 'adverb', 2, 'precisely so', 'on the very next page'),
  ('83ae8a3b-705b-5f02-a10a-fb4f63e3c560', '9abb23fc-3b7c-5996-95ac-1a8e60a1e8e8', 'adverb', 1, 'used as an intensive especially to indicate something unexpected', 'even an idiot knows that'),
  ('d4dd4113-2a8d-516a-9e00-f50e39adcb8f', '9abb23fc-3b7c-5996-95ac-1a8e60a1e8e8', 'adverb', 2, 'in spite of; notwithstanding', 'even when he is sick, he works'),
  ('7b63d077-0a4e-58c4-b091-d1fefd9cb08a', '039004da-4a2d-5f1b-85f3-89e2e6db3a39', 'adverb', 1, 'in or at this place; where the speaker or writer is', 'I work here'),
  ('a41070f2-f0f4-5ed3-97fd-cce5a8a9f7d1', '039004da-4a2d-5f1b-85f3-89e2e6db3a39', 'adverb', 2, 'in this circumstance or respect or on this point or detail', 'what do we have here?'),
  ('6af452f5-7b40-5f62-a9a3-6a6f2b35fe87', '91b19302-186a-5603-9f21-3c1f04f16586', 'noun', 1, 'a condition requiring relief', 'she satisfied his need for affection'),
  ('aea048bd-50fb-5855-bd4c-d2a17efa8c04', '91b19302-186a-5603-9f21-3c1f04f16586', 'noun', 2, 'anything that is necessary but lacking', 'he had sufficient means to meet his simple needs'),
  ('ea1acfda-34b8-5da2-b32a-a2a7f96ed161', '91b19302-186a-5603-9f21-3c1f04f16586', 'verb', 1, 'require as useful, just, or proper', 'It takes nerve to do what she did'),
  ('c82a9371-2ef2-51f5-927c-6643ef78adf2', '91b19302-186a-5603-9f21-3c1f04f16586', 'verb', 2, 'have need of', 'This piano wants the attention of a competent tuner'),
  ('89e6a4cd-60e9-5fe6-aebb-f994310fbfed', '8886637d-6f18-5ef3-823b-97079f5d9fd6', 'adverb', 1, 'in accordance with truth or fact or reality', 'she was now truly American'),
  ('dbb44de0-a0d2-5140-a362-554c62e99129', '8886637d-6f18-5ef3-823b-97079f5d9fd6', 'adverb', 2, 'in actual fact', 'to be nominally but not actually independent'),
  ('ca566447-a087-58b4-8384-5438e06a44a0', '8caa45e2-19f3-5f67-80ed-1d5f20821125', 'noun', 1, 'an abstract idea of that which is due to a person or governmental body by law or tradition or nature; ; - Eleanor Roosevelt', 'they are endowed by their Creator with certain unalienable Rights'),
  ('dcffaa70-573c-58b4-a5b2-78296ee27651', '8caa45e2-19f3-5f67-80ed-1d5f20821125', 'noun', 2, 'location near or direction toward the right side; i.e. the side to the south when a person or object faces east', 'he stood on the right'),
  ('3e849873-2577-5d97-94ce-c5fce2958f7c', '8caa45e2-19f3-5f67-80ed-1d5f20821125', 'adjective', 1, 'being or located on or directed toward the side of the body to the east when facing north', 'my right hand'),
  ('8d4f9783-158f-5433-bd37-93d6515cae66', '8caa45e2-19f3-5f67-80ed-1d5f20821125', 'adjective', 2, 'free from error; especially conforming to fact or truth', 'the correct answer'),
